mapper.select:
select distinct m.menu_id, m.parent_id, m.menu_name, m.path, m.component, m.menu_type, m.icon, m.order_num, m.create_time
from menu m where m.menu_type in ('M', 'C')
order by m.parent_id, m.order_num

mapper.update:
update menu
menu_name = #{menuName}, parent_id = #{parentId}, order_num = #{orderNum}, path = #{path}, component = #{component}, menu_type = #{menuType}, icon = #{icon},
where menu_id = #{menuId}
